  6→package repository
  7→
  8→import (
  9→	"database/sql"
 10→	"fmt"
 11→	"net/url"
 12→	"sync"
 13→	"time"
 14→
 15→	cclog "github.com/ClusterCockpit/cc-lib/v2/ccLogger"
 16→	"github.com/jmoiron/sqlx"
 17→	"github.com/mattn/go-sqlite3"
 18→	"github.com/qustavo/sqlhooks/v2"
 19→)
 20→
 21→var (
 22→	dbConnOnce     sync.Once
 23→	dbConnInstance *DBConnection
 24→)
 25→
 26→type DBConnection struct {
 27→	DB     *sqlx.DB
 28→	Driver string
 29→}
 30→
 31→type DatabaseOptions struct {
 32→	URL                   string
 33→	MaxOpenConnections    int
 34→	MaxIdleConnections    int
 35→	ConnectionMaxLifetime time.Duration
 36→	ConnectionMaxIdleTime time.Duration
 37→}
 38→
 39→func setupSqlite(db *sql.DB) error {
 40→	pragmas := []string{
 41→		"temp_store = memory",
 42→	}
 43→
 44→	for _, pragma := range pragmas {
 45→		_, err := db.Exec("PRAGMA " + pragma)
 46→		if err != nil {
 47→			return err
 48→		}
 49→	}
 50→
 51→	return nil
 52→}
 53→
 54→func Connect(db string) {
 55→	var err error
 56→	var dbHandle *sqlx.DB
 57→
 58→	dbConnOnce.Do(func() {
 59→		opts := DatabaseOptions{
 60→			URL:                   db,
 61→			MaxOpenConnections:    repoConfig.MaxOpenConnections,
 62→			MaxIdleConnections:    repoConfig.MaxIdleConnections,
 63→			ConnectionMaxLifetime: repoConfig.ConnectionMaxLifetime,
 64→			ConnectionMaxIdleTime: repoConfig.ConnectionMaxIdleTime,
 65→		}
 66→
 67→		// TODO: Have separate DB handles for Writes and Reads
 68→		// Optimize SQLite connection: https://kerkour.com/sqlite-for-servers
 69→		connectionURLParams := make(url.Values)
 70→		connectionURLParams.Add("_txlock", "immediate")
 71→		connectionURLParams.Add("_journal_mode", "WAL")
 72→		connectionURLParams.Add("_busy_timeout", "5000")
 73→		connectionURLParams.Add("_synchronous", "NORMAL")
 74→		connectionURLParams.Add("_cache_size", "1000000000")
 75→		connectionURLParams.Add("_foreign_keys", "true")
 76→		opts.URL = fmt.Sprintf("file:%s?%s", opts.URL, connectionURLParams.Encode())
 77→
 78→		if cclog.Loglevel() == "debug" {
 79→			sql.Register("sqlite3WithHooks", sqlhooks.Wrap(&sqlite3.SQLiteDriver{}, &Hooks{}))
 80→			dbHandle, err = sqlx.Open("sqlite3WithHooks", opts.URL)
 81→		} else {
 82→			dbHandle, err = sqlx.Open("sqlite3", opts.URL)
 83→		}
 84→
 85→		if err != nil {
 86→			cclog.Abortf("DB Connection: Could not connect to SQLite database with sqlx.Open().\nError: %s\n", err.Error())
 87→		}
 88→
 89→		err = setupSqlite(dbHandle.DB)
 90→		if err != nil {
 91→			cclog.Abortf("Failed sqlite db setup.\nError: %s\n", err.Error())
 92→		}
 93→
 94→		dbHandle.SetMaxOpenConns(opts.MaxOpenConnections)
 95→		dbHandle.SetMaxIdleConns(opts.MaxIdleConnections)
 96→		dbHandle.SetConnMaxLifetime(opts.ConnectionMaxLifetime)
 97→		dbHandle.SetConnMaxIdleTime(opts.ConnectionMaxIdleTime)
 98→
 99→		dbConnInstance = &DBConnection{DB: dbHandle}
100→		err = checkDBVersion(dbHandle.DB)
101→		if err != nil {
102→			cclog.Abortf("DB Connection: Failed DB version check.\nError: %s\n", err.Error())
103→		}
104→	})
105→}
106→
107→func GetConnection() *DBConnection {
108→	if dbConnInstance == nil {
109→		cclog.Fatalf("Database connection not initialized!")
110→	}
111→
112→	return dbConnInstance
113→}
114→
115→// ResetConnection closes the current database connection and resets the connection state.
116→// This function is intended for testing purposes only to allow test isolation.
117→func ResetConnection() error {
118→	if dbConnInstance != nil && dbConnInstance.DB != nil {
119→		if err := dbConnInstance.DB.Close(); err != nil {
120→			return fmt.Errorf("failed to close database connection: %w", err)
121→		}
122→	}
123→
124→	dbConnInstance = nil
125→	dbConnOnce = sync.Once{}
126→	jobRepoInstance = nil
127→	jobRepoOnce = sync.Once{}
128→	nodeRepoInstance = nil
129→	nodeRepoOnce = sync.Once{}
130→	userRepoInstance = nil
131→	userRepoOnce = sync.Once{}
132→	userCfgRepoInstance = nil
133→	userCfgRepoOnce = sync.Once{}
134→
135→	return nil
136→}
