  6→// Package repository provides job query functionality with filtering, pagination,
  7→// and security controls. This file contains the main query builders and security
  8→// checks for job retrieval operations.
  9→package repository
 10→
 11→import (
 12→	"context"
 13→	"errors"
 14→	"fmt"
 15→	"regexp"
 16→	"strings"
 17→	"time"
 18→
 19→	"github.com/ClusterCockpit/cc-backend/internal/config"
 20→	"github.com/ClusterCockpit/cc-backend/internal/graph/model"
 21→	cclog "github.com/ClusterCockpit/cc-lib/v2/ccLogger"
 22→	"github.com/ClusterCockpit/cc-lib/v2/schema"
 23→	sq "github.com/Masterminds/squirrel"
 24→)
 25→
 26→const (
 27→	// Default initial capacity for job result slices
 28→	defaultJobsCapacity = 50
 29→)
 30→
 31→// QueryJobs retrieves jobs from the database with optional filtering, pagination,
 32→// and sorting. Security controls are automatically applied based on the user context.
 33→//
 34→// Parameters:
 35→//   - ctx: Context containing user authentication information
 36→//   - filters: Optional job filters (cluster, state, user, time ranges, etc.)
 37→//   - page: Optional pagination parameters (page number and items per page)
 38→//   - order: Optional sorting specification (column or footprint field)
 39→//
 40→// Returns a slice of jobs matching the criteria, or an error if the query fails.
 41→// The function enforces role-based access control through SecurityCheck.
 42→func (r *JobRepository) QueryJobs(
 43→	ctx context.Context,
 44→	filters []*model.JobFilter,
 45→	page *model.PageRequest,
 46→	order *model.OrderByInput,
 47→) ([]*schema.Job, error) {
 48→	query, qerr := SecurityCheck(ctx, sq.Select(jobColumns...).From("job"))
 49→	if qerr != nil {
 50→		return nil, qerr
 51→	}
 52→
 53→	if order != nil {
 54→		field := toSnakeCase(order.Field)
 55→		if order.Type == "col" {
 56→			switch order.Order {
 57→			case model.SortDirectionEnumAsc:
 58→				query = query.OrderBy(fmt.Sprintf("job.%s ASC", field))
 59→			case model.SortDirectionEnumDesc:
 60→				query = query.OrderBy(fmt.Sprintf("job.%s DESC", field))
 61→			default:
 62→				return nil, errors.New("invalid sorting order for column")
 63→			}
 64→		} else {
 65→			// Order by footprint JSON field values
 66→			query = query.Where("JSON_VALID(meta_data)")
 67→			switch order.Order {
 68→			case model.SortDirectionEnumAsc:
 69→				query = query.OrderBy(fmt.Sprintf("JSON_EXTRACT(footprint, \"$.%s\") ASC", field))
 70→			case model.SortDirectionEnumDesc:
 71→				query = query.OrderBy(fmt.Sprintf("JSON_EXTRACT(footprint, \"$.%s\") DESC", field))
 72→			default:
 73→				return nil, errors.New("invalid sorting order for footprint")
 74→			}
 75→		}
 76→	}
 77→
 78→	if page != nil && page.ItemsPerPage != -1 {
 79→		limit := uint64(page.ItemsPerPage)
 80→		query = query.Offset((uint64(page.Page) - 1) * limit).Limit(limit)
 81→	}
 82→
 83→	for _, f := range filters {
 84→		query = BuildWhereClause(f, query)
 85→	}
 86→
 87→	rows, err := query.RunWith(r.stmtCache).Query()
 88→	if err != nil {
 89→		queryString, queryVars, _ := query.ToSql()
 90→		return nil, fmt.Errorf("query failed [%s] %v: %w", queryString, queryVars, err)
 91→	}
 92→	defer rows.Close()
 93→
 94→	jobs := make([]*schema.Job, 0, defaultJobsCapacity)
 95→	for rows.Next() {
 96→		job, err := scanJob(rows)
 97→		if err != nil {
 98→			cclog.Warnf("Error scanning job row: %v", err)
 99→			return nil, fmt.Errorf("failed to scan job row: %w", err)
100→		}
101→		jobs = append(jobs, job)
102→	}
103→
104→	if err := rows.Err(); err != nil {
105→		return nil, fmt.Errorf("error iterating job rows: %w", err)
106→	}
107→
108→	return jobs, nil
109→}
110→
111→// CountJobs returns the total number of jobs matching the given filters.
112→// Security controls are automatically applied based on the user context.
113→// Uses DISTINCT count to handle tag filters correctly (jobs may appear multiple
114→// times when joined with the tag table).
115→func (r *JobRepository) CountJobs(
116→	ctx context.Context,
117→	filters []*model.JobFilter,
118→) (int, error) {
119→	query, qerr := SecurityCheck(ctx, sq.Select("count(DISTINCT job.id)").From("job"))
120→	if qerr != nil {
121→		return 0, qerr
122→	}
123→
124→	for _, f := range filters {
125→		query = BuildWhereClause(f, query)
126→	}
127→
128→	var count int
129→	if err := query.RunWith(r.DB).Scan(&count); err != nil {
130→		return 0, fmt.Errorf("failed to count jobs: %w", err)
131→	}
132→
133→	return count, nil
134→}
135→
136→// SecurityCheckWithUser applies role-based access control filters to a job query
137→// based on the provided user's roles and permissions.
138→//
139→// Access rules by role:
140→//   - API role (exclusive): Full access to all jobs
141→//   - Admin/Support roles: Full access to all jobs
142→//   - Manager role: Access to jobs in managed projects plus own jobs
143→//   - User role: Access only to own jobs
144→//
145→// Returns an error if the user is nil or has no recognized roles.
146→func SecurityCheckWithUser(user *schema.User, query sq.SelectBuilder) (sq.SelectBuilder, error) {
147→	if user == nil {
148→		var qnil sq.SelectBuilder
149→		return qnil, fmt.Errorf("user context is nil")
150→	}
151→
152→	switch {
153→	case len(user.Roles) == 1 && user.HasRole(schema.RoleAPI):
154→		return query, nil
155→	case user.HasAnyRole([]schema.Role{schema.RoleAdmin, schema.RoleSupport}):
156→		return query, nil
157→	case user.HasRole(schema.RoleManager):
158→		if len(user.Projects) != 0 {
159→			return query.Where(sq.Or{sq.Eq{"job.project": user.Projects}, sq.Eq{"job.hpc_user": user.Username}}), nil
160→		}
161→		cclog.Debugf("Manager '%s' has no assigned projects, restricting to personal jobs", user.Username)
162→		return query.Where("job.hpc_user = ?", user.Username), nil
163→	case user.HasRole(schema.RoleUser):
164→		return query.Where("job.hpc_user = ?", user.Username), nil
165→	default:
166→		var qnil sq.SelectBuilder
167→		return qnil, fmt.Errorf("user has no or unknown roles")
168→	}
169→}
170→
171→// SecurityCheck extracts the user from the context and applies role-based access
172→// control filters to the query. This is a convenience wrapper around SecurityCheckWithUser.
173→func SecurityCheck(ctx context.Context, query sq.SelectBuilder) (sq.SelectBuilder, error) {
174→	user := GetUserFromContext(ctx)
175→	return SecurityCheckWithUser(user, query)
176→}
177→
178→// BuildWhereClause constructs SQL WHERE conditions from a JobFilter and applies
179→// them to the query. Supports filtering by job properties (cluster, state, user),
180→// time ranges, resource usage, tags, and JSON field searches in meta_data,
181→// footprint, and resources columns.
182→func BuildWhereClause(filter *model.JobFilter, query sq.SelectBuilder) sq.SelectBuilder {
183→	// Primary Key
184→	if filter.DbID != nil {
185→		dbIDs := make([]string, len(filter.DbID))
186→		copy(dbIDs, filter.DbID)
187→		query = query.Where(sq.Eq{"job.id": dbIDs})
188→	}
189→	// Explicit indices
190→	if filter.Cluster != nil {
191→		query = buildStringCondition("job.cluster", filter.Cluster, query)
192→	}
193→	if filter.SubCluster != nil {
194→		query = buildStringCondition("job.subcluster", filter.SubCluster, query)
195→	}
196→	if filter.Partition != nil {
197→		query = buildStringCondition("job.cluster_partition", filter.Partition, query)
198→	}
199→	if filter.State != nil {
200→		states := make([]string, len(filter.State))
201→		for i, val := range filter.State {
202→			states[i] = string(val)
203→		}
204→		query = query.Where(sq.Eq{"job.job_state": states})
205→	}
206→	if filter.Shared != nil {
207→		query = query.Where("job.shared = ?", *filter.Shared)
208→	}
209→	if filter.Project != nil {
210→		query = buildStringCondition("job.project", filter.Project, query)
211→	}
212→	if filter.User != nil {
213→		query = buildStringCondition("job.hpc_user", filter.User, query)
214→	}
215→	if filter.NumNodes != nil {
216→		query = buildIntCondition("job.num_nodes", filter.NumNodes, query)
217→	}
218→	if filter.NumAccelerators != nil {
219→		query = buildIntCondition("job.num_acc", filter.NumAccelerators, query)
220→	}
221→	if filter.NumHWThreads != nil {
222→		query = buildIntCondition("job.num_hwthreads", filter.NumHWThreads, query)
223→	}
224→	if filter.ArrayJobID != nil {
225→		query = query.Where("job.array_job_id = ?", *filter.ArrayJobID)
226→	}
227→	if filter.StartTime != nil {
228→		query = buildTimeCondition("job.start_time", filter.StartTime, query)
229→	}
230→	if filter.Duration != nil {
231→		query = buildIntCondition("job.duration", filter.Duration, query)
232→	}
233→	if filter.Energy != nil {
234→		query = buildFloatCondition("job.energy", filter.Energy, query)
235→	}
236→	// Indices on Tag Table
237→	if filter.Tags != nil {
238→		// This is an OR-Logic query: Returns all distinct jobs with at least one of the requested tags; TODO: AND-Logic query?
239→		query = query.Join("jobtag ON jobtag.job_id = job.id").Where(sq.Eq{"jobtag.tag_id": filter.Tags}).Distinct()
240→	}
241→	// No explicit Indices
242→	if filter.JobID != nil {
243→		query = buildStringCondition("job.job_id", filter.JobID, query)
244→	}
245→	// Queries Within JSONs
246→	if filter.MetricStats != nil {
247→		for _, ms := range filter.MetricStats {
248→			query = buildFloatJSONCondition(ms.MetricName, ms.Range, query)
249→		}
250→	}
251→	if filter.Node != nil {
252→		query = buildResourceJSONCondition("hostname", filter.Node, query)
253→	}
254→	if filter.JobName != nil {
255→		query = buildMetaJSONCondition("jobName", filter.JobName, query)
256→	}
257→	if filter.Schedule != nil {
258→		interactiveJobname := "interactive"
259→		switch *filter.Schedule {
260→		case "interactive":
261→			iFilter := model.StringInput{Eq: &interactiveJobname}
262→			query = buildMetaJSONCondition("jobName", &iFilter, query)
263→		case "batch":
264→			sFilter := model.StringInput{Neq: &interactiveJobname}
265→			query = buildMetaJSONCondition("jobName", &sFilter, query)
266→		}
267→	}
268→
269→	// Configurable Filter to exclude recently started jobs, see config.go: ShortRunningJobsDuration
270→	if filter.MinRunningFor != nil {
271→		now := time.Now().Unix()
272→		// Only jobs whose start timestamp is more than MinRunningFor seconds in the past
273→		// If a job completed within the configured timeframe, it will still show up after the start_time matches the condition!
274→		query = query.Where(sq.Lt{"job.start_time": (now - int64(*filter.MinRunningFor))})
275→	}
276→	return query
277→}
278→
279→// buildIntCondition creates a BETWEEN clause for integer range filters.
280→// Reminder: BETWEEN Queries are slower and dont use indices as frequently: Only use if both conditions required
281→func buildIntCondition(field string, cond *config.IntRange, query sq.SelectBuilder) sq.SelectBuilder {
282→	if cond.From != 0 && cond.To != 0 {
283→		return query.Where(field+" BETWEEN ? AND ?", cond.From, cond.To)
284→	} else if cond.From != 0 {
285→		return query.Where(field+" >= ?", cond.From)
286→	} else if cond.To != 0 {
287→		return query.Where(field+" <= ?", cond.To)
288→	} else {
289→		return query
290→	}
291→}
292→
293→// buildFloatCondition creates a BETWEEN clause for float range filters.
294→// Reminder: BETWEEN Queries are slower and dont use indices as frequently: Only use if both conditions required
295→func buildFloatCondition(field string, cond *model.FloatRange, query sq.SelectBuilder) sq.SelectBuilder {
296→	if cond.From != 0.0 && cond.To != 0.0 {
297→		return query.Where(field+" BETWEEN ? AND ?", cond.From, cond.To)
298→	} else if cond.From != 0.0 {
299→		return query.Where(field+" >= ?", cond.From)
300→	} else if cond.To != 0.0 {
301→		return query.Where(field+" <= ?", cond.To)
302→	} else {
303→		return query
304→	}
305→}
306→
307→// buildTimeCondition creates time range filters supporting absolute timestamps,
308→// relative time ranges (last6h, last24h, last7d, last30d), or open-ended ranges.
309→// Reminder: BETWEEN Queries are slower and dont use indices as frequently: Only use if both conditions required
310→func buildTimeCondition(field string, cond *config.TimeRange, query sq.SelectBuilder) sq.SelectBuilder {
311→	if cond.From != nil && cond.To != nil {
312→		return query.Where(field+" BETWEEN ? AND ?", cond.From.Unix(), cond.To.Unix())
313→	} else if cond.From != nil {
314→		return query.Where(field+" >= ?", cond.From.Unix())
315→	} else if cond.To != nil {
316→		return query.Where(field+" <= ?", cond.To.Unix())
317→	} else if cond.Range != "" {
318→		now := time.Now().Unix()
319→		var then int64
320→		switch cond.Range {
321→		case "last6h":
322→			then = now - (60 * 60 * 6)
323→		case "last24h":
324→			then = now - (60 * 60 * 24)
325→		case "last7d":
326→			then = now - (60 * 60 * 24 * 7)
327→		case "last30d":
328→			then = now - (60 * 60 * 24 * 30)
329→		default:
330→			cclog.Debugf("No known named timeRange: startTime.range = %s", cond.Range)
331→			return query
332→		}
333→		return query.Where(field+" >= ?", then)
334→	} else {
335→		return query
336→	}
337→}
338→
339→// buildFloatJSONCondition creates a filter on a numeric field within the footprint JSON column.
340→// Reminder: BETWEEN Queries are slower and dont use indices as frequently: Only use if both conditions required
341→func buildFloatJSONCondition(condName string, condRange *model.FloatRange, query sq.SelectBuilder) sq.SelectBuilder {
342→	query = query.Where("JSON_VALID(footprint)")
343→	if condRange.From != 0.0 && condRange.To != 0.0 {
344→		return query.Where("JSON_EXTRACT(footprint, \"$."+condName+"\") BETWEEN ? AND ?", condRange.From, condRange.To)
345→	} else if condRange.From != 0.0 {
346→		return query.Where("JSON_EXTRACT(footprint, \"$."+condName+"\") >= ?", condRange.From)
347→	} else if condRange.To != 0.0 {
348→		return query.Where("JSON_EXTRACT(footprint, \"$."+condName+"\") <= ?", condRange.To)
349→	} else {
350→		return query
351→	}
352→}
353→
354→// buildStringCondition creates filters for string fields supporting equality,
355→// inequality, prefix, suffix, substring, and IN list matching.
356→func buildStringCondition(field string, cond *model.StringInput, query sq.SelectBuilder) sq.SelectBuilder {
357→	if cond.Eq != nil {
358→		return query.Where(field+" = ?", *cond.Eq)
359→	}
360→	if cond.Neq != nil {
361→		return query.Where(field+" != ?", *cond.Neq)
362→	}
363→	if cond.StartsWith != nil {
364→		return query.Where(field+" LIKE ?", fmt.Sprint(*cond.StartsWith, "%"))
365→	}
366→	if cond.EndsWith != nil {
367→		return query.Where(field+" LIKE ?", fmt.Sprint("%", *cond.EndsWith))
368→	}
369→	if cond.Contains != nil {
370→		return query.Where(field+" LIKE ?", fmt.Sprint("%", *cond.Contains, "%"))
371→	}
372→	if cond.In != nil {
373→		queryElements := make([]string, len(cond.In))
374→		copy(queryElements, cond.In)
375→		return query.Where(sq.Or{sq.Eq{field: queryElements}})
376→	}
377→	return query
378→}
379→
380→// buildMetaJSONCondition creates filters on fields within the meta_data JSON column.
381→func buildMetaJSONCondition(jsonField string, cond *model.StringInput, query sq.SelectBuilder) sq.SelectBuilder {
382→	query = query.Where("JSON_VALID(meta_data)")
383→	if cond.Eq != nil {
384→		return query.Where("JSON_EXTRACT(meta_data, \"$."+jsonField+"\") = ?", *cond.Eq)
385→	}
386→	if cond.Neq != nil {
387→		return query.Where("JSON_EXTRACT(meta_data, \"$."+jsonField+"\") != ?", *cond.Neq)
388→	}
389→	if cond.StartsWith != nil {
390→		return query.Where("JSON_EXTRACT(meta_data, \"$."+jsonField+"\") LIKE ?", fmt.Sprint(*cond.StartsWith, "%"))
391→	}
392→	if cond.EndsWith != nil {
393→		return query.Where("JSON_EXTRACT(meta_data, \"$."+jsonField+"\") LIKE ?", fmt.Sprint("%", *cond.EndsWith))
394→	}
395→	if cond.Contains != nil {
396→		return query.Where("JSON_EXTRACT(meta_data, \"$."+jsonField+"\") LIKE ?", fmt.Sprint("%", *cond.Contains, "%"))
397→	}
398→	return query
399→}
400→
401→// buildResourceJSONCondition creates filters on fields within the resources JSON array column.
402→// Uses json_each to search within array elements.
403→func buildResourceJSONCondition(jsonField string, cond *model.StringInput, query sq.SelectBuilder) sq.SelectBuilder {
404→	query = query.Where("JSON_VALID(resources)")
405→	if cond.Eq != nil {
406→		return query.Where("EXISTS (SELECT 1 FROM json_each(job.resources) WHERE json_extract(value, \"$."+jsonField+"\") = ?)", *cond.Eq)
407→	}
408→	if cond.Neq != nil { // Currently Unused
409→		return query.Where("EXISTS (SELECT 1 FROM json_each(job.resources) WHERE json_extract(value, \"$."+jsonField+"\") != ?)", *cond.Neq)
410→	}
411→	if cond.StartsWith != nil { // Currently Unused
412→		return query.Where("EXISTS (SELECT 1 FROM json_each(job.resources) WHERE json_extract(value, \"$."+jsonField+"\")) LIKE ?)", fmt.Sprint(*cond.StartsWith, "%"))
413→	}
414→	if cond.EndsWith != nil { // Currently Unused
415→		return query.Where("EXISTS (SELECT 1 FROM json_each(job.resources) WHERE json_extract(value, \"$."+jsonField+"\") LIKE ?)", fmt.Sprint("%", *cond.EndsWith))
416→	}
417→	if cond.Contains != nil {
418→		return query.Where("EXISTS (SELECT 1 FROM json_each(job.resources) WHERE json_extract(value, \"$."+jsonField+"\") LIKE ?)", fmt.Sprint("%", *cond.Contains, "%"))
419→	}
420→	return query
421→}
422→
423→var (
424→	matchFirstCap = regexp.MustCompile("(.)([A-Z][a-z]+)")
425→	matchAllCap   = regexp.MustCompile("([a-z0-9])([A-Z])")
426→)
427→
428→// toSnakeCase converts camelCase strings to snake_case for SQL column names.
429→// Includes security checks to prevent SQL injection attempts.
430→// Panics if potentially dangerous characters are detected.
431→func toSnakeCase(str string) string {
432→	for _, c := range str {
433→		if c == '\'' || c == '\\' || c == '"' || c == ';' || c == '-' || c == ' ' {
434→			cclog.Panicf("toSnakeCase: potentially dangerous character detected in input: %q", str)
435→		}
436→	}
437→
438→	snake := matchFirstCap.ReplaceAllString(str, "${1}_${2}")
439→	snake = matchAllCap.ReplaceAllString(snake, "${1}_${2}")
440→	return strings.ToLower(snake)
441→}
