190→func (r *UserRepository) UpdateUser(dbUser *schema.User, user *schema.User) error {
191→	// user contains updated info -> Apply to dbUser
192→	// --- Simple Name Update ---
193→	if dbUser.Name != user.Name {
194→		if _, err := sq.Update("hpc_user").Set("name", user.Name).Where("hpc_user.username = ?", dbUser.Username).RunWith(r.DB).Exec(); err != nil {
195→			cclog.Errorf("error while updating name of user '%s'", user.Username)
196→			return err
197→		}
198→	}
199→
200→	// --- Def Helpers ---
201→	// Helper to update roles
202→	updateRoles := func(roles []string) error {
203→		rolesJSON, _ := json.Marshal(roles)
204→		_, err := sq.Update("hpc_user").Set("roles", rolesJSON).Where("hpc_user.username = ?", dbUser.Username).RunWith(r.DB).Exec()
205→		return err
206→	}
207→
208→	// Helper to update projects
209→	updateProjects := func(projects []string) error {
210→		projectsJSON, _ := json.Marshal(projects)
211→		_, err := sq.Update("hpc_user").Set("projects", projectsJSON).Where("hpc_user.username = ?", dbUser.Username).RunWith(r.DB).Exec()
212→		return err
213→	}
214→
215→	// Helper to clear projects
216→	clearProjects := func() error {
217→		_, err := sq.Update("hpc_user").Set("projects", "[]").Where("hpc_user.username = ?", dbUser.Username).RunWith(r.DB).Exec()
218→		return err
219→	}
220→
221→	// --- Manager Role Handling ---
222→	if dbUser.HasRole(schema.RoleManager) && user.HasRole(schema.RoleManager) && !reflect.DeepEqual(dbUser.Projects, user.Projects) {
223→		// Existing Manager: update projects
224→		if err := updateProjects(user.Projects); err != nil {
225→			return err
226→		}
227→	} else if dbUser.HasRole(schema.RoleUser) && user.HasRole(schema.RoleManager) && user.HasNotRoles([]schema.Role{schema.RoleAdmin}) {
228→		// New Manager: update roles and projects
229→		if err := updateRoles(user.Roles); err != nil {
230→			return err
231→		}
232→		if err := updateProjects(user.Projects); err != nil {
233→			return err
234→		}
235→	} else if dbUser.HasRole(schema.RoleManager) && user.HasNotRoles([]schema.Role{schema.RoleAdmin, schema.RoleManager}) {
236→		// Remove Manager: update roles and clear projects
237→		if err := updateRoles(user.Roles); err != nil {
238→			return err
239→		}
240→		if err := clearProjects(); err != nil {
241→			return err
242→		}
243→	}
244→
245→	// --- Support Role Handling ---
246→	if dbUser.HasRole(schema.RoleUser) && dbUser.HasNotRoles([]schema.Role{schema.RoleSupport}) &&
247→		user.HasRole(schema.RoleSupport) && user.HasNotRoles([]schema.Role{schema.RoleAdmin}) {
248→		// New Support: update roles
249→		if err := updateRoles(user.Roles); err != nil {
250→			return err
251→		}
252→	} else if dbUser.HasRole(schema.RoleSupport) && user.HasNotRoles([]schema.Role{schema.RoleAdmin, schema.RoleSupport}) {
253→		// Remove Support: update roles
254→		if err := updateRoles(user.Roles); err != nil {
255→			return err
256→		}
257→	}
258→
259→	return nil
260→}
