422→func (r *UserRepository) RemoveProject(ctx context.Context, username string, project string) error {
423→	user, err := r.GetUser(username)
424→	if err != nil {
425→		return err
426→	}
427→
428→	if !user.HasRole(schema.RoleManager) {
429→		return fmt.Errorf("user '%#v' is not a manager", username)
430→	}
431→
432→	if !user.HasProject(project) {
433→		return fmt.Errorf("user '%#v': Cannot remove project '%#v' - Does not match", username, project)
434→	}
435→
436→	var exists bool
437→	var newprojects []string
438→	for _, p := range user.Projects {
439→		if p != project {
440→			newprojects = append(newprojects, p) // Append all projects not matching requested to be deleted project
441→		} else {
442→			exists = true
443→		}
444→	}
445→
446→	if exists {
447→		var result any
448→		if len(newprojects) == 0 {
449→			result = "[]"
450→		} else {
451→			result, _ = json.Marshal(newprojects)
452→		}
453→		if _, err := sq.Update("hpc_user").Set("projects", result).Where("hpc_user.username = ?", username).RunWith(r.DB).Exec(); err != nil {
454→			return err
455→		}
456→		return nil
457→	} else {
458→		return fmt.Errorf("user %s already does not manage project %s", username, project)
459→	}
460→}
