476→func (r *UserRepository) FetchUserInCtx(ctx context.Context, username string) (*model.User, error) {
477→	me := GetUserFromContext(ctx)
478→	if me != nil && me.Username != username &&
479→		me.HasNotRoles([]schema.Role{schema.RoleAdmin, schema.RoleSupport, schema.RoleManager}) {
480→		return nil, errors.New("forbidden")
481→	}
