488→			/* This warning will be logged *often* for non-local users, i.e. users mentioned only in job-table or archive, */
489→			/* since FetchUser will be called to retrieve full name and mail for every job in query/list									 */
490→			// cclog.Warnf("User '%s' Not found in DB", username)
491→			return nil, nil
492→		}
493→
494→		cclog.Warnf("Error while fetching user '%s'", username)
495→		return nil, err
496→	}
497→
498→	user.Name = name.String
499→	user.Email = email.String
500→	return user, nil
